## Data Model

### Automation Rule Schema

```typescript
interface Automation {
  id: string;                    // Unique identifier
  name: string;                  // User-friendly name
  description?: string;          // Optional description
  enabled: boolean;              // Is rule active?
  scope: 'global' | 'project' | 'board';  // Where rule applies
  trigger: AutomationTrigger;    // What starts the rule
  conditions: AutomationCondition[];  // When to execute
  actions: AutomationAction[];   // What to do
  createdAt: string;             // ISO timestamp
  updatedAt: string;             // ISO timestamp
  createdBy: string;             // User ID
}
```

### Trigger Types

```typescript
type AutomationTrigger =
  | { type: 'onCreate'; entity: 'task' | 'event' | 'doc' }
  | { type: 'onUpdate'; field: string }
  | { type: 'onMove'; to: string }  // Column/status change
  | { type: 'onDue'; leadMinutes: number }  // Before due date
  | { type: 'cron'; expr: string };  // Scheduled (5-field cron)

// Examples:
// onCreate: When a new task is created
// onUpdate: When a specific field changes (e.g., status, priority)
// onMove: When task moves to specific column
// onDue: When task becomes due (or X minutes before)
// cron: On a schedule (e.g., "0 2 * * *" = daily at 2am)
```

### Condition Types

```typescript
interface AutomationCondition {
  lhs: string;  // Left-hand side (field name or expression)
  op: '==' | '!=' | '<' | '<=' | '>' | '>=' | 'includes' | 'matches';
  rhs: string | number | boolean;  // Right-hand side (value)
}

// Examples:
// { lhs: 'status', op: '==', rhs: 'Done' }
// { lhs: 'priority', op: '>=', rhs: 3 }
// { lhs: 'tags', op: 'includes', rhs: 'urgent' }
// { lhs: 'title', op: 'matches', rhs: '^Bug:' }  // Regex
```

### Action Types

```typescript
type AutomationAction =
  | { type: 'set'; field: string; value: any }
  | { type: 'move'; to: string }  // Move to column/status
  | { type: 'addTag'; tag: string }
  | { type: 'removeTag'; tag: string }
  | { type: 'create'; entity: 'task' | 'event' | 'doc'; payload: object }
  | { type: 'notify'; target: 'local' | 'push' | 'email' | 'webhook'; message: string }
  | { type: 'snooze'; deltaMinutes: number };

// Examples:
// { type: 'set', field: 'priority', value: 5 }
// { type: 'move', to: 'Done' }
// { type: 'addTag', tag: 'overdue' }
// { type: 'notify', target: 'local', message: 'Task overdue!' }
// { type: 'snooze', deltaMinutes: 1440 }  // Snooze 1 day
```

