## Storage

### IndexedDB Stores

```typescript
// Store 1: automations
interface AutomationRecord {
  id: string;
  ...Automation;  // Full automation object
}

// Store 2: runs
interface AutomationRun {
  id: string;
  automationId: string;
  triggerId: string;      // What triggered this run
  startedAt: string;
  completedAt: string | null;
  status: 'running' | 'success' | 'error';
  error?: string;
  actionsExecuted: number;
  mutations: object[];    // What changed
}

// Store 3: schedules
interface AutomationSchedule {
  automationId: string;
  nextRunAt: string;      // ISO timestamp
  cronExpr: string;
}

// Store 4: queue
interface AutomationQueueItem {
  id: string;
  automationId: string;
  payload: object;
  enqueuedAt: string;
  attempts: number;
}
```

